%[text] # 例3.11（バイラテラルフィルタ）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example03_11"; % mfilename

imgname = "msipimg02";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## フィルタ処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]

%%
%[text] ## ガウシアンフィルタ
sigmam = 0.5;
f = fspecial('gaussian',3,sigmam);
Yg = imfilter(X,f,'corr','same');
figure(2) %[output:3785ec24]
imshow(Yg) %[output:3785ec24]
title('ガウシアンフィルタ')  %[output:3785ec24]

%%
%[text] ## バイラテラルフィルタ
sigmax = 0.1;
Yb = imbilatfilt(X,'degreeOfSmoothing',sigmax^2,'spatialSigma',sigmam,'NeighborhoodSize',3,'Padding',0);
figure(3) %[output:202a9de9]
imshow(Yb) %[output:202a9de9]
title('バイラテラルフィルタ')  %[output:202a9de9]

%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,"fig03-07a.png"))
imwrite(Yg,fullfile(resfolder,"fig03-07b.png"))
imwrite(Yb,fullfile(resfolder,"fig03-07c.png"))

